import{_ as e,o,c as n,ag as r}from"./chunks/framework.ePeAWSvT.js";const g=JSON.parse('{"title":"Authentication Methods","description":"","frontmatter":{},"headers":[],"relativePath":"guide/reference-authentication.md","filePath":"guide/reference-authentication.md"}'),a={name:"guide/reference-authentication.md"};function s(i,t,d,c,h,u){return o(),n("div",null,[...t[0]||(t[0]=[r('<h1 id="authentication-methods" tabindex="-1">Authentication Methods <a class="header-anchor" href="#authentication-methods" aria-label="Permalink to &quot;Authentication Methods&quot;">​</a></h1><p>Central supports several authentication methods for connecting to external systems. The set available depends on whether you&#39;re using a pre-built <a href="./build-connectors.html">Connector</a>, defining your own custom connector, or configuring a <a href="./build-custom-extensions.html">Custom Extension</a>.</p><h2 id="supported-methods" tabindex="-1">Supported Methods <a class="header-anchor" href="#supported-methods" aria-label="Permalink to &quot;Supported Methods&quot;">​</a></h2><p>The platform supports the following authentication methods. Some are only available through pre-built connectors and are not selectable when building a connector from scratch — see <a href="#available-for-custom-connectors">Available for Custom Connectors</a> below.</p><table tabindex="0"><thead><tr><th>Method</th><th>Description</th></tr></thead><tbody><tr><td><strong>Unauthenticated</strong></td><td>No authentication; the request is sent as-is.</td></tr><tr><td><strong>Basic</strong></td><td>HTTP Basic Authentication using a username and password.</td></tr><tr><td><strong>OAuth — Client Credential</strong></td><td>OAuth 2.0 client credentials grant (machine-to-machine).</td></tr><tr><td><strong>OAuth — Authorization Code</strong></td><td>OAuth 2.0 authorization code flow, with refresh tokens for ongoing access.</td></tr><tr><td><strong>OAuth — JWT Client Assertion</strong></td><td>OAuth 2.0 using a signed JWT as the client assertion.</td></tr><tr><td><strong>OAuth — Password Credential</strong></td><td>OAuth 2.0 resource owner password credentials grant.</td></tr><tr><td><strong>Custom</strong></td><td>Authentication logic specific to a pre-built connector.</td></tr><tr><td><strong>Customized</strong></td><td>Request-based authentication driven by connector configuration.</td></tr><tr><td><strong>Passthrough</strong></td><td>Authentication settings are passed directly to each endpoint action.</td></tr><tr><td><strong>XML</strong></td><td>XML-based authentication used by certain SOAP-style connectors.</td></tr><tr><td><strong>BigQuery</strong></td><td>Service-account authentication for Google BigQuery.</td></tr></tbody></table><h2 id="available-for-custom-connectors" tabindex="-1">Available for Custom Connectors <a class="header-anchor" href="#available-for-custom-connectors" aria-label="Permalink to &quot;Available for Custom Connectors&quot;">​</a></h2><p>When defining a new connector yourself (rather than using a pre-built one), the following methods are available:</p><ul><li><strong>Unauthenticated</strong></li><li><strong>Basic</strong></li><li><strong>OAuth Client Credential</strong></li><li><strong>Passthrough</strong></li></ul><p>The remaining methods listed above ship as part of specific pre-built connectors and are not selectable when creating a custom connector.</p><h2 id="available-for-custom-extensions" tabindex="-1">Available for Custom Extensions <a class="header-anchor" href="#available-for-custom-extensions" aria-label="Permalink to &quot;Available for Custom Extensions&quot;">​</a></h2><p><a href="./build-custom-extensions.html">Custom Extensions</a> currently support <strong>OAuth Client Credential</strong> only.</p><h2 id="multi-method-connectors" tabindex="-1">Multi-Method Connectors <a class="header-anchor" href="#multi-method-connectors" aria-label="Permalink to &quot;Multi-Method Connectors&quot;">​</a></h2><p>Some pre-built connectors support more than one authentication method, letting you pick the option that best matches your tenant&#39;s security posture (e.g., an OAuth-code flow that requires a registered Public Application versus a Static Token your IT team can issue without that registration).</p><p>When you create or edit one of these connectors, an <strong>Authentication Type</strong> dropdown appears on the Configure step. Selecting an entry updates the Secure Settings list to match that method. Credentials that are shared between methods (for example, <code>ClientId</code> and <code>ClientSecret</code> between OAuth-code and Resource Owner Password) are preserved when you switch, so you can pivot during setup without re-entering shared values.</p><p>The following connectors currently expose multiple methods:</p><table tabindex="0"><thead><tr><th>Connector</th><th>Methods</th></tr></thead><tbody><tr><td><strong>Egnyte</strong></td><td>OAuth — Authorization Code · OAuth — Password Credential · Static Token (Passthrough)</td></tr></tbody></table>',16)])])}const p=e(a,[["render",s]]);export{g as __pageData,p as default};
